import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface HourlyForecast {
  hour: string;
  uvIndex: number;
}

interface UVData {
  location: string;
  current: {
    uvIndex: number;
    riskCategory: string;
  };
  hourlyForecast: HourlyForecast[];
}

export default function Widget() {
  const uvData = response.data as UVData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              {uvData.location}
            </Typography>
            <Typography variant="h6" fontWeight={600} sx={{ my: 0.5 }}>
              Current UV Index: {uvData.current.uvIndex}
            </Typography>
            <Chip
              label={uvData.current.riskCategory}
              sx={{ fontSize: '12px', bgcolor: '#FF5722', color: '#FFFFFF', fontWeight: 'bold' }}
            />
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: uvData.hourlyForecast.map(forecast => forecast.uvIndex),
                  color: '#FFC107',
                  label: 'UV Index',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: uvData.hourlyForecast.map(forecast => forecast.hour),
                  id: 'hours',
                },
              ]}
              yAxis={[{ id: 'uvIndex' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis
                axisId="hours"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="uvIndex"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
